import 'package:flutter_dotenv/flutter_dotenv.dart';

class AppCredentials {
  static String get awsAccessKeyId =>
      dotenv.env['AWS_ACCESS_KEY_ID'] ?? _throwMissing('AWS_ACCESS_KEY_ID');

  static String get awsSecretAccessKey =>
      dotenv.env['AWS_SECRET_ACCESS_KEY'] ??
      _throwMissing('AWS_SECRET_ACCESS_KEY');

  static String get awsRegion =>
      dotenv.env['AWS_REGION'] ?? 'us-east-1';

  static String get awsS3Bucket =>
      dotenv.env['AWS_S3_BUCKET'] ?? _throwMissing('AWS_S3_BUCKET');

  static String get googleCloudVisionApiKey =>
      dotenv.env['GOOGLE_CLOUD_VISION_API_KEY'] ??
      _throwMissing('GOOGLE_CLOUD_VISION_API_KEY');

  static Never _throwMissing(String key) {
    throw Exception(
      'Missing environment variable: $key\n'
      'Create a .env file in the project root with the required keys.\n'
      'See .env.example for reference.',
    );
  }

  static bool get isConfigured {
    try {
      awsAccessKeyId;
      awsSecretAccessKey;
      awsS3Bucket;
      googleCloudVisionApiKey;
      return true;
    } catch (_) {
      return false;
    }
  }
}


