import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import 'package:mime/mime.dart';
import 'package:path/path.dart' as path;
import 'package:uuid/uuid.dart';
import '../config/credentials.dart';

class AwsS3Service {
  final String _accessKeyId;
  final String _secretAccessKey;
  final String _region;
  final String _bucket;

  AwsS3Service()
      : _accessKeyId = AppCredentials.awsAccessKeyId,
        _secretAccessKey = AppCredentials.awsSecretAccessKey,
        _region = AppCredentials.awsRegion,
        _bucket = AppCredentials.awsS3Bucket;

  String get _host => '$_bucket.s3.$_region.amazonaws.com';
  String get _baseUrl => 'https://$_host';

  Future<S3UploadResult> uploadFile(File file) async {
    final bytes = await file.readAsBytes();
    final extension = path.extension(file.path);
    final key = 'uploads/${const Uuid().v4()}$extension';
    final contentType =
        lookupMimeType(file.path) ?? 'application/octet-stream';

    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);

    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'Host': _host,
      'Content-Type': contentType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
    };

    final authorization = _generateAuthorizationHeader(
      method: 'PUT',
      uri: '/$key',
      queryParams: {},
      headers: headers,
      payloadHash: payloadHash,
      dateStamp: dateStamp,
      amzDate: amzDate,
    );

    headers['Authorization'] = authorization;

    final url = Uri.parse('$_baseUrl/$key');

    final response = await http.put(
      url,
      headers: headers,
      body: bytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      final publicUrl = '$_baseUrl/$key';
      return S3UploadResult(
        success: true,
        url: publicUrl,
        key: key,
        message: 'Upload successful',
      );
    } else {
      return S3UploadResult(
        success: false,
        url: null,
        key: null,
        message:
            'Upload failed: ${response.statusCode} - ${response.body}',
      );
    }
  }

  Future<S3UploadResult> uploadBytes({
    required Uint8List bytes,
    required String fileName,
    String? contentType,
  }) async {
    final extension = path.extension(fileName);
    final key = 'uploads/${const Uuid().v4()}$extension';
    final mimeType = contentType ??
        lookupMimeType(fileName) ??
        'application/octet-stream';

    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);

    final payloadHash = sha256.convert(bytes).toString();

    final headers = <String, String>{
      'Host': _host,
      'Content-Type': mimeType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
    };

    final authorization = _generateAuthorizationHeader(
      method: 'PUT',
      uri: '/$key',
      queryParams: {},
      headers: headers,
      payloadHash: payloadHash,
      dateStamp: dateStamp,
      amzDate: amzDate,
    );

    headers['Authorization'] = authorization;

    final url = Uri.parse('$_baseUrl/$key');

    final response = await http.put(
      url,
      headers: headers,
      body: bytes,
    );

    if (response.statusCode == 200 || response.statusCode == 201) {
      final publicUrl = '$_baseUrl/$key';
      return S3UploadResult(
        success: true,
        url: publicUrl,
        key: key,
        message: 'Upload successful',
      );
    } else {
      return S3UploadResult(
        success: false,
        url: null,
        key: null,
        message:
            'Upload failed: ${response.statusCode} - ${response.body}',
      );
    }
  }

  String _generateAuthorizationHeader({
    required String method,
    required String uri,
    required Map<String, String> queryParams,
    required Map<String, String> headers,
    required String payloadHash,
    required String dateStamp,
    required String amzDate,
  }) {
    final canonicalUri = Uri.encodeFull(uri);

    final sortedQueryKeys = queryParams.keys.toList()..sort();
    final canonicalQueryString = sortedQueryKeys
        .map((k) =>
            '${Uri.encodeComponent(k)}=${Uri.encodeComponent(queryParams[k]!)}')
        .join('&');

    final sortedHeaderKeys = headers.keys
        .map((k) => k.toLowerCase())
        .toList()
      ..sort();
    final canonicalHeaders = sortedHeaderKeys
        .map((k) => '$k:${headers[headers.keys.firstWhere(
              (hk) => hk.toLowerCase() == k,
            )]!.trim()}')
        .join('\n');
    final signedHeaders = sortedHeaderKeys.join(';');

    final canonicalRequest = [
      method,
      canonicalUri,
      canonicalQueryString,
      '$canonicalHeaders\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$_region/s3/aws4_request';

    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(dateStamp);
    final signature = Hmac(sha256, signingKey)
        .convert(utf8.encode(stringToSign))
        .toString();

    return 'AWS4-HMAC-SHA256 '
        'Credential=$_accessKeyId/$credentialScope, '
        'SignedHeaders=$signedHeaders, '
        'Signature=$signature';
  }

  List<int> _getSignatureKey(String dateStamp) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$_secretAccessKey'))
        .convert(utf8.encode(dateStamp))
        .bytes;
    final kRegion =
        Hmac(sha256, kDate).convert(utf8.encode(_region)).bytes;
    final kService =
        Hmac(sha256, kRegion).convert(utf8.encode('s3')).bytes;
    final kSigning =
        Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

  String _formatDate(DateTime dt) =>
      '${dt.year}${dt.month.toString().padLeft(2, '0')}${dt.day.toString().padLeft(2, '0')}';

  String _formatAmzDate(DateTime dt) =>
      '${_formatDate(dt)}T${dt.hour.toString().padLeft(2, '0')}${dt.minute.toString().padLeft(2, '0')}${dt.second.toString().padLeft(2, '0')}Z';
}

class S3UploadResult {
  final bool success;
  final String? url;
  final String? key;
  final String message;

  S3UploadResult({
    required this.success,
    this.url,
    this.key,
    required this.message,
  });

  @override
  String toString() =>
      'S3UploadResult(success: $success, url: $url, message: $message)';
}


