import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:http/http.dart' as http;
import '../config/credentials.dart';

class GoogleVisionService {
  static const String _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';

  final String _apiKey;

  GoogleVisionService()
      : _apiKey = AppCredentials.googleCloudVisionApiKey;

  Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    final bytes = await imageFile.readAsBytes();
    return analyzeImageBytes(bytes);
  }

  Future<VisionAnalysisResult> analyzeImageBytes(Uint8List bytes) async {
    final base64Image = base64Encode(bytes);

    final requestBody = {
      'requests': [
        {
          'image': {
            'content': base64Image,
          },
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 15},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'FACE_DETECTION', 'maxResults': 10},
            {'type': 'LANDMARK_DETECTION', 'maxResults': 5},
            {'type': 'SAFE_SEARCH_DETECTION'},
            {'type': 'IMAGE_PROPERTIES'},
            {'type': 'WEB_DETECTION', 'maxResults': 5},
          ],
        }
      ]
    };

    final url = Uri.parse('$_baseUrl?key=$_apiKey');

    final response = await http.post(
      url,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      final responses = data['responses'] as List;

      if (responses.isEmpty) {
        return VisionAnalysisResult(
          success: true,
          labels: [],
          objects: [],
          texts: [],
          faces: [],
          landmarks: [],
          safeSearch: null,
          dominantColors: [],
          webEntities: [],
          rawResponse: data,
        );
      }

      final result = responses[0] as Map<String, dynamic>;
      return _parseResponse(result, data);
    } else {
      final errorData = jsonDecode(response.body);
      final errorMessage = errorData['error']?['message'] ?? 'Unknown error';
      return VisionAnalysisResult.error(
        'Vision API error (${response.statusCode}): $errorMessage',
      );
    }
  }

  VisionAnalysisResult _parseResponse(
    Map<String, dynamic> result,
    Map<String, dynamic> rawResponse,
  ) {
    // Labels
    final labels = (result['labelAnnotations'] as List?)
            ?.map((l) => VisionLabel(
                  description: l['description'] ?? '',
                  score: (l['score'] as num?)?.toDouble() ?? 0.0,
                  topicality: (l['topicality'] as num?)?.toDouble() ?? 0.0,
                ))
            .toList() ??
        [];

    // Objects
    final objects = (result['localizedObjectAnnotations'] as List?)
            ?.map((o) => VisionObject(
                  name: o['name'] ?? '',
                  score: (o['score'] as num?)?.toDouble() ?? 0.0,
                ))
            .toList() ??
        [];

    // Text
    final texts = (result['textAnnotations'] as List?)
            ?.map((t) => VisionText(
                  description: t['description'] ?? '',
                  locale: t['locale'] ?? '',
                ))
            .toList() ??
        [];

    // Faces
    final faces = (result['faceAnnotations'] as List?)
            ?.map((f) => VisionFace(